var body = $input.first().json.body || $input.first().json;
var UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!body.tenantId || !UUID_RE.test(body.tenantId)) throw new Error('tenantId requis (UUID)');
if (!body.facturxId || !UUID_RE.test(body.facturxId)) throw new Error('facturxId requis (UUID)');
return [{ json: { tenantId: body.tenantId, facturxId: body.facturxId } }];

var facturx = $('05. Get Facturx').all().map(function(i) { return i.json; }).filter(function(e) { return e.id; });
if (facturx.length === 0) throw new Error('Factur-X introuvable');
var fx = facturx[0];

var STATUTS = {
  generee: { label: 'Générée', code: 'GENERATED', description: 'Facture générée, en attente de transmission' },
  transmise: { label: 'Transmise', code: 'TRANSMITTED', description: 'Facture transmise au PPF/PDP' },
  acceptee: { label: 'Acceptée', code: 'ACCEPTED', description: 'Facture acceptée par le destinataire' },
  refusee: { label: 'Refusée', code: 'REJECTED', description: 'Facture refusée par le destinataire' }
};

var currentStatus = STATUTS[fx.statut] || { label: fx.statut, code: 'UNKNOWN', description: 'Statut inconnu' };

var ppfInfo = 'Non transmise';
if (fx.plateforme === 'PPF') ppfInfo = 'Déposée au PPF - ID: ' + (fx.identifiant_ppf || 'N/A');
if (fx.plateforme === 'PDP') ppfInfo = 'Déposée au PDP - ID: ' + (fx.identifiant_ppf || 'N/A');

return [{ json: {
  success: true,
  facturx: {
    id: fx.id,
    factureId: fx.facture_id,
    numeroFacture: fx.numero_facture || null,
    montantTtc: parseFloat(fx.montant_ttc) || 0,
    clientNom: fx.client_nom || null,
    format: fx.format,
    profil: fx.profil
  },
  statut: {
    code: currentStatus.code,
    label: currentStatus.label,
    description: currentStatus.description
  },
  transmission: {
    plateforme: fx.plateforme || null,
    identifiantPpf: fx.identifiant_ppf || null,
    dateTransmission: fx.date_transmission || null,
    info: ppfInfo
  },
  dates: {
    generation: fx.date_generation,
    transmission: fx.date_transmission || null,
    verification: new Date().toISOString()
  }
} }];
